import{_ as e,o as a,c as r,ag as i}from"./chunks/framework.DNt_9s2P.js";const u=JSON.parse('{"title":"概要","description":"","frontmatter":{},"headers":[],"relativePath":"guide/index.md","filePath":"guide/index.md"}'),n={name:"guide/index.md"};function d(o,t,l,s,h,c){return a(),r("div",null,[...t[0]||(t[0]=[i('<h1 id="概要" tabindex="-1">概要 <a class="header-anchor" href="#概要" aria-label="Permalink to &quot;概要&quot;">​</a></h1><p><strong>Selah</strong> は関西学院大学の教務システム KWIC、学習管理システム Luna (LMS)、大学の Microsoft 365 メールを統合し、ネイティブデスクトップアプリとして提供する非公式クライアントです。</p><h2 id="なぜ-selah" tabindex="-1">なぜ Selah？ <a class="header-anchor" href="#なぜ-selah" aria-label="Permalink to &quot;なぜ Selah？&quot;">​</a></h2><p>関学生の日常では、授業情報の確認のために KWIC、課題の提出のために Luna、メールの確認のために Office 365 と複数のブラウザタブを行き来する必要があります。Selah はこれらを 1 つのアプリに統合し、よりスムーズな学習体験を提供します。</p><h2 id="主な特徴" tabindex="-1">主な特徴 <a class="header-anchor" href="#主な特徴" aria-label="Permalink to &quot;主な特徴&quot;">​</a></h2><ul><li><strong>ワンクリック SSO ログイン</strong> -- 関学の SSO 認証に対応。一度のログインで KWIC・Luna・メールすべてにアクセス</li><li><strong>高速起動</strong> -- SQLite によるローカルキャッシュと SWR 方式で、ネットワーク待ちなしに即座にデータを表示</li><li><strong>ネイティブ通知</strong> -- 新着お知らせ・課題をデスクトップ通知でお届け</li><li><strong>AI アシスト</strong> -- OpenAI / Gemini API を活用した履修分析・学習計画生成</li><li><strong>オフライン対応</strong> -- キャッシュされたデータでネット不通時も閲覧可能</li><li><strong>クロスプラットフォーム</strong> -- macOS と Windows に対応</li></ul><h2 id="技術スタック" tabindex="-1">技術スタック <a class="header-anchor" href="#技術スタック" aria-label="Permalink to &quot;技術スタック&quot;">​</a></h2><p>Selah は <a href="https://tauri.app/" target="_blank" rel="noreferrer">Tauri 2</a> をベースに構築されています。</p><table tabindex="0"><thead><tr><th>コンポーネント</th><th>技術</th></tr></thead><tbody><tr><td>フレームワーク</td><td>Tauri 2 (Rust + WebView)</td></tr><tr><td>フロントエンド</td><td>Svelte 5 + TypeScript + Vite</td></tr><tr><td>バックエンド</td><td>Rust (reqwest, scraper, rusqlite)</td></tr><tr><td>ローカル DB</td><td>SQLite (WAL モード)</td></tr><tr><td>AI 統合</td><td>OpenAI API / Google Gemini API</td></tr><tr><td>デスクトップ統合</td><td>macOS: WKWebView, Apple Calendar / Windows: WebView2, NSIS</td></tr></tbody></table><h2 id="ライセンス" tabindex="-1">ライセンス <a class="header-anchor" href="#ライセンス" aria-label="Permalink to &quot;ライセンス&quot;">​</a></h2><p>Selah は <a href="https://github.com/mirai-mamori/Selah/blob/main/LICENSE" target="_blank" rel="noreferrer">MIT License</a> の下で公開されています。</p>',11)])])}const S=e(n,[["render",d]]);export{u as __pageData,S as default};
